namespace sv_60d746accdb64db6b1190b872eeda319.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

using sv_60d746accdb64db6b1190b872eeda319.Models;

namespace sv_60d746accdb64db6b1190b872eeda319.Services;

public class MockSettingsService : ISettingsService
{
    private UserProfile _profile = new(
        "Jane Doe",
        "jane.doe@example.com",
        "https://i.pravatar.cc/150?u=jane",
        "Full-stack developer passionate about clean code and great UX.");

    private NotificationPrefs _notificationPrefs = new(
        EmailNotifications: true,
        PushNotifications: true,
        WeeklyDigest: false,
        MutedChannels: ["marketing", "random"]);

    private SecuritySettings _security = new(
        TwoFactorEnabled: true,
        LastPasswordChange: DateTime.UtcNow.AddDays(-45),
        Sessions:
        [
            new("sess-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
            new("sess-2", "Safari on iPhone", "New York, US", DateTime.UtcNow.AddHours(-2)),
            new("sess-3", "Firefox on Linux", "London, UK", DateTime.UtcNow.AddDays(-3)),
        ]);

    private AppearanceSettings _appearance = new("Light", "Medium", "English", false);

    // All available channels for the notifications section
    private readonly List<string> _allChannels =
        ["general", "engineering", "marketing", "design", "random", "announcements"];

    public Task<UserProfile> GetProfileAsync()
        => Task.FromResult(_profile);

    public Task SaveProfileAsync(UserProfile profile)
    {
        _profile = profile;
        return Task.CompletedTask;
    }

    public Task<NotificationPrefs> GetNotificationPrefsAsync()
    {
        // Ensure the muted channels list includes all available channels info
        // by returning prefs as-is; the component uses _allChannels via a separate mechanism
        return Task.FromResult(_notificationPrefs);
    }

    public Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        _notificationPrefs = prefs;
        return Task.CompletedTask;
    }

    public Task<SecuritySettings> GetSecuritySettingsAsync()
        => Task.FromResult(_security);

    public Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        _security = _security with { LastPasswordChange = DateTime.UtcNow };
        return Task.CompletedTask;
    }

    public Task RevokeSessionAsync(string sessionId)
    {
        var updated = _security.Sessions.Where(s => s.Id != sessionId).ToList();
        _security = _security with { Sessions = updated };
        return Task.CompletedTask;
    }

    public Task<AppearanceSettings> GetAppearanceAsync()
        => Task.FromResult(_appearance);

    public Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        _appearance = settings;
        return Task.CompletedTask;
    }

    public List<string> GetAllChannels() => _allChannels;
}

