@using sv_60d746accdb64db6b1190b872eeda319.Models

<div class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <nav class="sidebar-nav">
        @foreach (var section in Sections)
        {
            <button class="sidebar-item @(section == ActiveSection ? "active" : "")"
                    @onclick="() => OnSectionChanged.InvokeAsync(section)">
                <span class="sidebar-icon">@GetIcon(section)</span>
                <span>@section</span>
            </button>
        }
    </nav>
</div>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@using sv_60d746accdb64db6b1190b872eeda319.Models

<div class="settings-section">
    <h4>Profile</h4>
    <p class="text-muted">Manage your personal information</p>

    @if (_profile is not null)
    {
        <div class="profile-form">
            <div class="avatar-area mb-3">
                <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
                <div class="mt-2">
                    <label class="form-label">Avatar URL</label>
                    <input type="text" class="form-control" @bind="_avatarUrl" />
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>

            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="3" @bind="_bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
                <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
            </div>

            @if (_showSuccess)
            {
                <div class="alert alert-success mt-3 fade-in" role="alert">
                    ✅ Profile saved successfully!
                </div>
            }
        </div>
    }
    else
    {
        <p>Loading profile...</p>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _profile;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && _profile != Profile)
        {
            _profile = Profile;
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        if (_profile is null) return;
        _displayName = _profile.DisplayName;
        _email = _profile.Email;
        _avatarUrl = _profile.AvatarUrl;
        _bio = _profile.Bio;
    }

    private async Task SaveAsync()
    {
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await OnSave.InvokeAsync(updated);
        _profile = updated;
        _showSuccess = true;
        StateHasChanged();
        await Task.Delay(3000);
        _showSuccess = false;
    }

    private void Discard()
    {
        LoadFromProfile();
        _showSuccess = false;
    }
}

@using sv_60d746accdb64db6b1190b872eeda319.Models

<div class="settings-section">
    <h4>Notifications</h4>
    <p class="text-muted">Control how you receive notifications</p>

    @if (_prefs is not null)
    {
        <div class="mb-4">
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@_emailNotifications"
                       @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@_pushNotifications"
                       @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <h6>Muted Channels</h6>
        <div class="channel-list mb-3">
            @foreach (var channel in AllChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel @(isMuted ? "(muted)" : "")
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">
                ✅ Notification preferences saved!
            </div>
        }
    }
    else
    {
        <p>Loading notification preferences...</p>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public List<string> AllChannels { get; set; } = [];
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && _prefs != Prefs)
        {
            _prefs = Prefs;
            _emailNotifications = _prefs.EmailNotifications;
            _pushNotifications = _prefs.PushNotifications;
            _weeklyDigest = _prefs.WeeklyDigest;
            _mutedChannels = new List<string>(_prefs.MutedChannels);
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted && !_mutedChannels.Contains(channel))
            _mutedChannels.Add(channel);
        else if (!muted)
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var updated = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, new List<string>(_mutedChannels));
        await OnSave.InvokeAsync(updated);
        _prefs = updated;
        _showSuccess = true;
        StateHasChanged();
        await Task.Delay(3000);
        _showSuccess = false;
    }
}

@using sv_60d746accdb64db6b1190b872eeda319.Models

@if (Visible)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    @if (Session is not null)
                    {
                        <p>Are you sure you want to revoke this session?</p>
                        <ul class="list-unstyled mb-0">
                            <li><strong>Device:</strong> @Session.Device</li>
                            <li><strong>Location:</strong> @Session.Location</li>
                            <li><strong>Last Active:</strong> @Session.LastActive.ToString("g")</li>
                        </ul>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_60d746accdb64db6b1190b872eeda319.Models

<div class="settings-section">
    <h4>Security</h4>
    <p class="text-muted">Manage your account security</p>

    @if (_security is not null)
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <hr />

        <div class="mb-4">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-2">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_security.TwoFactorEnabled" disabled />
                    <label class="form-check-label" for="twoFactor">
                        @(_security.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </label>
                </div>
                <span class="badge @(_security.TwoFactorEnabled ? "bg-success" : "bg-warning")">
                    @(_security.TwoFactorEnabled ? "✓ Active" : "⚠ Inactive")
                </span>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-1">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>

        <hr />

        <h6>Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _security.Sessions)
                    {
                        var isCurrent = session.Id == _security.Sessions[0].Id;
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => ShowRevokeDialog(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <RevokeSessionDialog Visible="_showRevokeDialog"
                             Session="_sessionToRevoke"
                             OnConfirm="ConfirmRevoke"
                             OnCancel="CancelRevoke" />
    }
    else
    {
        <p>Loading security settings...</p>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string current, string newPwd)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private SecuritySettings? _security;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override void OnParametersSet()
    {
        if (Security is not null)
            _security = Security;
    }

    private async Task HandleChangePassword((string current, string newPwd) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_60d746accdb64db6b1190b872eeda319.Models

<div class="settings-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize how the app looks and feels</p>

    @if (_settings is not null)
    {
        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h6>Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
