@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public List<string> AllChannels { get; set; } = [];
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && _prefs != Prefs)
        {
            _prefs = Prefs;
            _emailNotifications = _prefs.EmailNotifications;
            _pushNotifications = _prefs.PushNotifications;
            _weeklyDigest = _prefs.WeeklyDigest;
            _mutedChannels = new List<string>(_prefs.MutedChannels);
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted && !_mutedChannels.Contains(channel))
            _mutedChannels.Add(channel);
        else if (!muted)
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var updated = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, new List<string>(_mutedChannels));
        await OnSave.InvokeAsync(updated);
        _prefs = updated;
        _showSuccess = true;
        StateHasChanged();
        await Task.Delay(3000);
        _showSuccess = false;
    }
}

