<div class="settings-section">
    <h4>Security</h4>
    <p class="text-muted">Manage your account security</p>

    @if (_security is not null)
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <hr />

        <div class="mb-4">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-2">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_security.TwoFactorEnabled" disabled />
                    <label class="form-check-label" for="twoFactor">
                        @(_security.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </label>
                </div>
                <span class="badge @(_security.TwoFactorEnabled ? "bg-success" : "bg-warning")">
                    @(_security.TwoFactorEnabled ? "✓ Active" : "⚠ Inactive")
                </span>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-1">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>

        <hr />

        <h6>Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _security.Sessions)
                    {
                        var isCurrent = session.Id == _security.Sessions[0].Id;
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => ShowRevokeDialog(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <RevokeSessionDialog Visible="_showRevokeDialog"
                             Session="_sessionToRevoke"
                             OnConfirm="ConfirmRevoke"
                             OnCancel="CancelRevoke" />
    }
    else
    {
        <p>Loading security settings...</p>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string current, string newPwd)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private SecuritySettings? _security;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override void OnParametersSet()
    {
        if (Security is not null)
            _security = Security;
    }

    private async Task HandleChangePassword((string current, string newPwd) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

