{"file_text": "<div class="change-password-panel">
    <button class="btn btn-link p-0 mb-2 text-decoration-none" @onclick="ToggleExpand">
        <span class="me-1">@(_expanded ? "▼" : "▶")</span> Change Password
    </button>

    @if (_expanded)
    {
        <div class="password-form border rounded p-3">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger py-2">@_error</div>
            }
            @if (_success)
            {
                <div class="alert alert-success py-2">✅ Password updated successfully!</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_updating">
                @(_updating ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string current, string newPwd)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _success;
    private bool _updating;

    private void ToggleExpand() => _expanded = !_expanded;

    private async Task UpdatePasswordAsync()
    {
        _error = null;
        _success = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _error = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _error = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _error = "Passwords do not match.";
            return;
        }

        _updating = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _updating = false;
        _success = true;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";

        StateHasChanged();
        await Task.Delay(3000);
        _success = false;
    }
}
