@using sv_60d746accdb64db6b1190b872eeda319.Models

<div class="settings-section">
    <h4>Notifications</h4>
    <p class="text-muted">Control how you receive notifications</p>

    @if (_prefs is not null)
    {
        <div class="mb-4">
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@_emailNotifications"
                       @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@_pushNotifications"
                       @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <h6>Muted Channels</h6>
        <div class="channel-list mb-3">
            @foreach (var channel in AllChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel @(isMuted ? "(muted)" : "")
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">
                ✅ Notification preferences saved!
            </div>
        }
    }
    else
    {
        <p>Loading notification preferences...</p>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public List<string> AllChannels { get; set; } = [];
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && _prefs != Prefs)
        {
            _prefs = Prefs;
            _emailNotifications = _prefs.EmailNotifications;
            _pushNotifications = _prefs.PushNotifications;
            _weeklyDigest = _prefs.WeeklyDigest;
            _mutedChannels = new List<string>(_prefs.MutedChannels);
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted && !_mutedChannels.Contains(channel))
            _mutedChannels.Add(channel);
        else if (!muted)
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var updated = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, new List<string>(_mutedChannels));
        await OnSave.InvokeAsync(updated);
        _prefs = updated;
        _showSuccess = true;
        StateHasChanged();
        await Task.Delay(3000);
        _showSuccess = false;
    }
}

