@using sv_60d746accdb64db6b1190b872eeda319.Models

@if (Visible)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    @if (Session is not null)
                    {
                        <p>Are you sure you want to revoke this session?</p>
                        <ul class="list-unstyled mb-0">
                            <li><strong>Device:</strong> @Session.Device</li>
                            <li><strong>Location:</strong> @Session.Location</li>
                            <li><strong>Last Active:</strong> @Session.LastActive.ToString("g")</li>
                        </ul>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_60d746accdb64db6b1190b872eeda319.Models

<div class="settings-section">
    <h4>Security</h4>
    <p class="text-muted">Manage your account security</p>

    @if (_security is not null)
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <hr />

        <div class="mb-4">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-2">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_security.TwoFactorEnabled" disabled />
                    <label class="form-check-label" for="twoFactor">
                        @(_security.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </label>
                </div>
                <span class="badge @(_security.TwoFactorEnabled ? "bg-success" : "bg-warning")">
                    @(_security.TwoFactorEnabled ? "✓ Active" : "⚠ Inactive")
                </span>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-1">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>

        <hr />

        <h6>Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
