@using sv_60d746accdb64db6b1190b872eeda319.Models

<div class="settings-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize how the app looks and feels</p>

    @if (_settings is not null)
    {
        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h6>Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6>Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" @bind="_language">
                        <option value="English">English</option>
                        <option value="Spanish">Spanish</option>
                        <option value="French">French</option>
                        <option value="German">German</option>
                        <option value="Japanese">Japanese</option>
                        <option value="Chinese">Chinese</option>
                    </select>
                </div>

                <div class="mb-4">
                    <h6>Compact Mode</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        <label class="form-check-label" for="compactMode">
                            @(_compactMode ? "On" : "Off")
                        </label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync">Save</button>

                @if (_showSuccess)
                {
                    <div class="alert alert-success mt-3 fade-in" role="alert">
                        ✅ Appearance settings saved!
                    </div>
                }
            </div>

            <div class="col-md-6">
                <h6>Live Preview</h6>
                <div class="preview-area @GetPreviewClasses()">
                    <div class="preview-header">Application Header</div>
                    <div class="preview-content">
                        <p class="preview-text">This is how your content will look with the selected settings.</p>
                        <div class="preview-card">
                            <strong>Sample Card</strong>
                            <p class="mb-0">Card content preview</p>
                        </div>
                        <button class="btn btn-sm btn-primary mt-2">Sample Button</button>
                    </div>
                    <div class="preview-footer">
                        Theme: @_theme · Font: @_fontSize · @(_compactMode ? "Compact" : "Standard")
                    </div>
                </div>
            </div>
        </div>
    }
    else
    {
        <p>Loading appearance settings...</p>
    }
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private AppearanceSettings? _settings;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Settings is not null && _settings != Settings)
        {
            _settings = Settings;
            _theme = _settings.Theme;
            _fontSize = _settings.FontSize;
            _language = _settings.Language;
            _compactMode = _settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string> { "preview-box" };
        classes.Add($"preview-theme-{_theme.ToLowerInvariant()}");
        classes.Add($"preview-font-{_fontSize.ToLowerInvariant()}");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _settings = updated;
        _showSuccess = true;
        StateHasChanged();
        await Task.Delay(3000);
        _showSuccess = false;
    }
}

