@page "/settings"
@using sv_60d746accdb64db6b1190b872eeda319.Models
@using sv_60d746accdb64db6b1190b872eeda319.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="s => { _activeSection = s; }" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection Profile="@_profile" OnSave="SaveProfileAsync" />
                break;
            case "Notifications":
                <NotificationsSection Prefs="@_notificationPrefs"
                                       AllChannels="@_allChannels"
                                       OnSave="SaveNotificationPrefsAsync" />
                break;
            case "Security":
                <SecuritySection Security="@_security"
                                  OnChangePassword="HandleChangePasswordAsync"
                                  OnRevokeSession="HandleRevokeSessionAsync" />
                break;
            case "Appearance":
                <AppearanceSection Settings="@_appearance" OnSave="SaveAppearanceAsync" />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;
    private List<string> _allChannels = [];

    protected override async Task OnInitializedAsync()
    {
        await LoadAllDataAsync();
    }

    private async Task LoadAllDataAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notificationPrefs = notifsTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;

        if (SettingsService is MockSettingsService mock)
            _allChannels = mock.GetAllChannels();
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task HandleChangePasswordAsync((string current, string newPwd) args)
    {
        await SettingsService.ChangePasswordAsync(args.current, args.newPwd);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleRevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

