/* ── Settings Dashboard Layout ── */
.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 100px);
    gap: 0;
}

/* ── Sidebar ── */
.settings-sidebar {
    width: 240px;
    min-width: 240px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem;
    margin-bottom: 1rem;
    font-weight: 600;
    color: #495057;
}

.sidebar-nav {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.65rem 1.25rem;
    border: none;
    background: none;
    text-align: left;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: all 0.15s ease;
    width: 100%;
}

.sidebar-item:hover {
    background: #e9ecef;
    color: #212529;
}

.sidebar-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.sidebar-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

/* ── Content Area ── */
.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 900px;
}

.settings-section h4 {
    margin-bottom: 0.25rem;
    font-weight: 600;
}

.settings-section .text-muted {
    margin-bottom: 1.5rem;
    font-size: 0.9rem;
}

/* ── Profile ── */
.avatar-preview {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-area > div {
    flex: 1;
}

/* ── Appearance Preview ── */
.preview-box {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.3s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    font-weight: 600;
    border-bottom: 1px solid rgba(0,0,0,0.1);
}

.preview-content {
    padding: 1rem;
}

.preview-card {
    border: 1px solid rgba(0,0,0,0.1);
    border-radius: 6px;
    padding: 0.75rem;
    margin-top: 0.5rem;
}

.preview-footer {
    padding: 0.5rem 1rem;
    font-size: 0.8rem;
    border-top: 1px solid rgba(0,0,0,0.1);
    opacity: 0.7;
}

/* Theme variants */
.preview-theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-theme-light .preview-header {
    background: #f8f9fa;
}

.preview-theme-dark {
    background: #1e1e1e;
    color: #e0e0e0;
}

.preview-theme-dark .preview-header {
    background: #2d2d2d;
}

.preview-theme-dark .preview-card {
    background: #2d2d2d;
    border-color: #444;
}

.preview-theme-dark .preview-footer {
    border-color: #444;
}

.preview-theme-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e1e 50%);
    color: #212529;
}

.preview-theme-system .preview-header {
    background: #e9ecef;
}

/* Font size variants */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.2rem;
}

/* Compact mode */
.preview-compact .preview-header,
.preview-compact .preview-content,
.preview-compact .preview-footer {
    padding-top: 0.35rem;
    padding-bottom: 0.35rem;
}

.preview-compact .preview-card {
    padding: 0.4rem;
    margin-top: 0.25rem;
}

.preview-text {
    margin-bottom: 0.5rem;
}

/* ── Toast animation ── */
.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-8px); }
    to { opacity: 1; transform: translateY(0); }
}

/* ── Modal backdrop fix ── */
.modal-backdrop.show {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    z-index: 1040;
}

.modal.d-block {
    z-index: 1050;
}

/* ── Password panel ── */
.password-form {
    max-width: 400px;
    background: #f8f9fa;
}

